(function(){function init(){if(!$docsify.modified){const req=new XMLHttpRequest();req.open('GET',document.location,!1);req.send(null);$docsify.modified=req.getResponseHeader('last-modified')}}
    const after=html=>{let footer=[`<hr/>`,`<small>`,`<div class="my-footer">`,`<div class="copyright"><a href="https://www.codedevils.org">CodeDevils</a> &copy; 2019. All rights reserved.</div>`,`<div class="modified">`,`Site modified: `+$docsify.modified,`</div>`,`</div>`,`</small>`].join('');return html+footer};const addFooter=hook=>{init();hook.afterEach(html=>after(html))};$docsify.plugins=[].concat(addFooter,$docsify.plugins)}())